#!/usr/bin/env bash
# topic-4.sh — 案例 决策助手 for 音乐制作 / 混音.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="音乐制作 / 混音"
TOPIC="案例"

usage() {
  cat <<EOF
topic-4.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-4.sh             # interactive
  ./topic-4.sh --dry-run   # walk through but no file
  ./topic-4.sh --json      # JSON to stdout
  ./topic-4.sh --explain   # show backing playbook rules + mental models
  ./topic-4.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 案例 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 准备定稿/交付（混音 print 前、母带交付前） → 则 **在尽量多的真实回放环境复核**：折 mono 查相位、过手机/车载/耳机、降到对话音量校平衡、母带预演多平台 nor
  • 如果 混音听起来"糊（mud）/挤/刺耳（harsh）" → 则 **先做减法 EQ（减 200-500Hz mud / 2-5kHz harsh）清出空间，再考虑加色**，必要时用动态
  • 如果 想让元素"更厚、更有冲击力又不想压扁瞬态" → 则 **用并行压缩（NY compression）：干信号保瞬态 + 一路重压副本垫底并行混合**，而不是把单链压得更狠。案

相关心智模型:
  • 服务歌优先于服务技术 (serve the song): 技术、音色、个人风格全都服从于"这首歌要表达什么"——好不好的最终裁判是情绪与歌本身，不是参数表（"if it sounds good, it is good"）。
  • 减法优先 / 每个处理都要能说出理由 (less but knowing why): 默认不处理；做得太多而非太少是这一行最常见的病——加任何东西（轨/EQ/压缩/响度）之前，先确认能不能减、不加，且每一次处理都要能讲出"我为什么这么做"。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "准备定稿/交付（混音 print 前、母带交付前）"
  "混音听起来\"糊（mud）/挤/刺耳（harsh）\""
  "想让元素\"更厚、更有冲击力又不想压扁瞬态\""
)
declare -a RULE_ACTIONS=(
  "**在尽量多的真实回放环境复核**：折 mono 查相位、过手机/车载/耳机、降到对话音量校平衡、母带预演多平台 normalization、多格式（含 Atmos 时附立体声兜底）。案例：CLA\"低音量监听是真 secret\"；混音 mono 兼容是相位检查的硬关卡（T03-S001 / T01-S037）"
  "**先做减法 EQ（减 200-500Hz mud / 2-5kHz harsh）清出空间，再考虑加色**，必要时用动态 EQ/soothe 压共振；不要一不够就 boost。案例：subtractive EQ 是 canon 跨多源共识的混音第一性手法（T04-S001 / T02-S001）"
  "**用并行压缩（NY compression）：干信号保瞬态 + 一路重压副本垫底并行混合**，而不是把单链压得更狠。案例：起于 1970-80s 纽约棚 SSL/1176 重压劈分；Brauer 把它发展成 multing 多总线分压、Scheps 发展成 3-bus（T04-S018 / T04-S017）"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-4-decision"
fi
